133	// 读取 token 用量数据（直接从 .data TSV 文件聚合）
134	let tokenUsageData = { days: [] };
135	const TOKEN_USAGE_DIR = path.join(__dirname, 'token-usage');
136	if (fs.existsSync(TOKEN_USAGE_DIR)) {
137	    const dayMap = {};
138	    const dataFiles = fs.readdirSync(TOKEN_USAGE_DIR).filter(f => /^\d{4}-\d{2}-\d{2}(_.+)?\.data$/.test(f)).sort();
139	    for (const df of dataFiles) {
140	        const date = df.replace(/_.+$/, '').replace(/\.data$/, ''); // Extract YYYY-MM-DD
141	        const lines = fs.readFileSync(path.join(TOKEN_USAGE_DIR, df), 'utf-8').trim().split('\n');
142	        if (lines.length < 2) continue; // header only
143	        const header = lines[0].split('\t');
144	        const tokens = { input: 0, output: 0, cache_read: 0, cache_creation: 0, reasoning: 0 };
145	        for (let i = 1; i < lines.length; i++) {
146	            const cols = lines[i].split('\t');
147	            const get = (name) => parseInt(cols[header.indexOf(name)] || '0', 10) || 0;
148	            tokens.input += get('tokens_input');
149	            tokens.output += get('tokens_output');
150	            tokens.cache_read += get('tokens_cache_read');
151	            tokens.cache_creation += get('tokens_cache_creation');
152	            tokens.reasoning += get('tokens_reasoning');
153	        }
154	        if (!dayMap[date]) dayMap[date] = { input: 0, output: 0, cache_read: 0, cache_creation: 0, reasoning: 0 };
155	        dayMap[date].input += tokens.input;
156	        dayMap[date].output += tokens.output;
157	        dayMap[date].cache_read += tokens.cache_read;
158	        dayMap[date].cache_creation += tokens.cache_creation;
159	        dayMap[date].reasoning += tokens.reasoning;
160	    }
161	    tokenUsageData.days = Object.keys(dayMap).sort().map(date => ({
162	        date,
163	        total_tokens: dayMap[date]
164	    }));
165	}
